const searchMessages = `-- name: SearchMessages :many
SELECT
	m.message_id,
	m.session_id,
	m.seq_no,
	m.role,
	m.content,
	m.tool_output,
	m.created_at,
	s.title,
	s.description
FROM agent_messages m
JOIN agent_sessions s ON s.user_id = m.user_id AND s.session_id = m.session_id
WHERE m.user_id = $1
  AND m.status = $2
  AND s.status <> $3
  AND m.hidden = 0
  AND m.role <> 'tool'
  AND (m.content ILIKE $4::text ESCAPE '\' OR m.tool_output ILIKE $4::text ESCAPE '\')
ORDER BY m.created_at DESC
LIMIT $6::int OFFSET $5::int
`

type SearchMessagesParams struct {
	UserID      string `json:"user_id"`
	Status      int32  `json:"status"`
	Status_2    int32  `json:"status_2"`
	Pattern     string `json:"pattern"`
	OffsetCount int32  `json:"offset_count"`
	LimitCount  int32  `json:"limit_count"`
}

type SearchMessagesRow struct {
	MessageID   string    `json:"message_id"`
	SessionID   string    `json:"session_id"`
	SeqNo       int64     `json:"seq_no"`
	Role        string    `json:"role"`
	Content     string    `json:"content"`
	ToolOutput  string    `json:"tool_output"`
	CreatedAt   time.Time `json:"created_at"`
	Title       string    `json:"title"`
	Description string    `json:"description"`
}

func (q *Queries) SearchMessages(ctx context.Context, arg SearchMessagesParams) ([]SearchMessagesRow, error) {
	rows, err := q.db.QueryContext(ctx, searchMessages,
		arg.UserID,
		arg.Status,
		arg.Status_2,
		arg.Pattern,
		arg.OffsetCount,
		arg.LimitCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []SearchMessagesRow{}
	for rows.Next() {
		var i SearchMessagesRow
		if err := rows.Scan(
			&i.MessageID,
			&i.SessionID,
			&i.SeqNo,
			&i.Role,
			&i.Content,
			&i.ToolOutput,
			&i.CreatedAt,
			&i.Title,
			&i.Description,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

